const api = require('/opt/homebrew/lib/node_modules/9router/src/cli/api/client.js');
const KEY = 'REDACTED';
const https = require('https');
const http = require('http');

function fetch(url, headers={}) {
  return new Promise((resolve, reject) => {
    const lib = url.startsWith('https') ? https : http;
    const req = lib.get(url, { headers, timeout: 20000 }, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => resolve({ status: res.statusCode, data }));
    });
    req.on('error', reject);
    req.on('timeout', () => { req.destroy(); reject(new Error('timeout')); });
  });
}

(async () => {
  console.log('enabling tunnel (single attempt)...');
  const on = await api.enableTunnel();
  console.log('enable:', JSON.stringify(on));

  let url = null;
  for (let i = 0; i < 30; i++) {
    await new Promise(r => setTimeout(r, 1000));
    const st = await api.getTunnelStatus();
    const t = st.data.tunnel;
    process.stdout.write(`poll ${i}: enabled=${t.enabled} running=${t.running} url=${t.tunnelUrl || '-'}\n`);
