# Tiny rewrite proxy: map /chat/completions -> /v1/chat/completions etc.
mkdir -p /Users/amin/.9router/proxy
cat > /Users/amin/.9router/proxy/cursor-v1-rewrite.js <<'EOF'
#!/usr/bin/env node
/**
 * Cursor sometimes requests /chat/completions instead of /v1/chat/completions
 * when Override Base URL ends with /v1 (absolute-path join drops the prefix).
 * This proxy rewrites OpenAI-style paths onto 9router's /v1/* API.
 */
const http = require('http');

const UPSTREAM_HOST = process.env.UPSTREAM_HOST || '127.0.0.1';
const UPSTREAM_PORT = Number(process.env.UPSTREAM_PORT || 20128);
const LISTEN_PORT = Number(process.env.LISTEN_PORT || 20129);

const REWRITE_PREFIXES = [
  '/chat/',
  '/models',
  '/embeddings',
  '/responses',
  '/audio/',
  '/images/',
  '/fine_tuning/',
  '/files',
  '/batches',
];

function rewriteUrl(url) {
  if (!url) return url;
  const q = url.indexOf('?');
  const path = q >= 0 ? url.slice(0, q) : url;
  const qs = q >= 0 ? url.slice(q) : '';
  if (path === '/v1' || path.startsWith('/v1/')) return url;
  if (path === '/' || path.startsWith('/_next') || path.startsWith('/dashboard') || path.startsWith('/api/')) {
    return url;
  }
  for (const p of REWRITE_PREFIXES) {
    if (path === p.replace(/\/$/, '') || path.startsWith(p)) {
      return '/v1' + path + qs;
    }
  }
  return url;
}

const server = http.createServer((req, res) => {
  const original = req.url || '/';
  const rewritten = rewriteUrl(original);
  if (rewritten !== original) {
    console.log(`[rewrite] ${req.method} ${original} -> ${rewritten}`);
  }

  const opts = {
    hostname: UPSTREAM_HOST,
    port: UPSTREAM_PORT,
    path: rewritten,
    method: req.method,
    headers: { ...req.headers, host: `${UPSTREAM_HOST}:${UPSTREAM_PORT}` },
  };

  const proxyReq = http.request(opts, (proxyRes) => {
    res.writeHead(proxyRes.statusCode || 502, proxyRes.headers);
    proxyRes.pipe(res);
  });
  proxyReq.on('error', (err) => {
    console.error('[upstream]', err.message);
    res.writeHead(502, { 'content-type': 'application/json' });
    res.end(JSON.stringify({ error: { message: 'upstream unavailable: ' + err.message } }));
  });
  req.pipe(proxyReq);
});

server.listen(LISTEN_PORT, '127.0.0.1', () => {
  console.log(`cursor-v1-rewrite listening on 127.0.0.1:${LISTEN_PORT} -> ${UPSTREAM_HOST}:${UPSTREAM_PORT}`);
});
EOF

